import{_ as e}from"./plugin-vue_export-helper-c27b6911.js";import{o as c,c as o,e as d}from"./app-be253e4c.js";const l={},a=d(`<h1 id="less命令" tabindex="-1"><a class="header-anchor" href="#less命令" aria-hidden="true">#</a> less命令</h1><p><code>less</code>命令的作用与<code>more</code>相似，都可以用来浏览文件的内容，用<code>less</code>命令显示文件时，使用<code>pageup</code>键向上翻页，使用<code>pagedown</code>键向下翻页，使用<code>↑</code>与<code>↓</code>按行浏览，使用<code>q</code>退出浏览，<code>less</code>在加载时不必读整个文件，加载速度会比<code>more</code>更快，<code>less</code>退出后<code>shell</code>不会留下刚显示的内容，而<code>more</code>退出后会在<code>shell</code>上留下刚显示的内容。</p><h2 id="语法" tabindex="-1"><a class="header-anchor" href="#语法" aria-hidden="true">#</a> 语法</h2><div class="language-bash" data-ext="sh"><pre class="language-bash"><code><span class="token function">less</span> <span class="token punctuation">[</span>option<span class="token punctuation">]</span> <span class="token punctuation">[</span>file<span class="token punctuation">]</span>
</code></pre></div><h2 id="参数" tabindex="-1"><a class="header-anchor" href="#参数" aria-hidden="true">#</a> 参数</h2><ul><li><code>-b &lt;buffer size&gt;</code>: 设置缓冲区的大小。</li><li><code>-e</code>: 当文件显示结束后，自动离开。</li><li><code>-f</code>: 强迫打开特殊文件，例如外围设备代号、目录和二进制文件。</li><li><code>-g</code>: 只标志最后搜索的关键词。</li><li><code>-i</code>: 忽略搜索时的大小写。</li><li><code>-m</code>: 显示类似<code>more</code>命令的百分比。</li><li><code>-N</code>: 显示每行的行号。</li><li><code>-o &lt;file&gt;</code>: 将<code>less</code>输出的内容在指定文件中保存起来。</li><li><code>-Q</code>: 不使用警告音。</li><li><code>-s</code>: 显示连续空行为一行。</li><li><code>-S</code>: 行过长时将超出部分舍弃。</li><li><code>-x &lt;num&gt;</code>: 将<code>tab</code>键显示为规定的数字空格。</li></ul><h2 id="常用操作" tabindex="-1"><a class="header-anchor" href="#常用操作" aria-hidden="true">#</a> 常用操作</h2><ul><li><code>ctrl + F</code>: 向前移动一屏。</li><li><code>ctrl + B</code>: 向后移动一屏。</li><li><code>ctrl + D</code>: 向前移动半屏。</li><li><code>ctrl + U</code>: 向后移动半屏。</li><li><code>j</code>: 向前移动一行</li><li><code>k</code>: 向后移动一行</li><li><code>/string</code>: 向下搜索字符串的功能。</li><li><code>?string</code>: 向上搜索字符串的功能。</li><li><code>n</code>: 重复前一个搜索，与<code>/</code>或<code>?</code>有关。</li><li><code>N</code>: 反向重复前一个搜索，与<code>/</code>或<code>?</code>有关。</li><li><code>b</code>: 向上翻一页。</li><li><code>d</code>: 向后翻半页。</li><li><code>h</code>: 显示帮助界面。</li><li><code>Q</code>: 退出<code>less</code>命令。</li><li><code>u</code>: 向前滚动半页。</li><li><code>y</code>: 向前滚动一行。</li><li><code>space</code>: 滚动一页。</li><li><code>enter</code>: 滚动一行。</li><li><code>pageup</code>: 向上翻动一页。</li><li><code>pagedown</code>: 向下翻动一页。</li><li><code>G</code>: 移动到最后一行。</li><li><code>g</code>: 移动到第一行。</li><li><code>q / ZZ</code>: 退出<code>less</code>命令。</li><li><code>v</code>: 使用配置的编辑器编辑当前文件。</li><li><code>h</code>: 显示<code>less</code>的帮助文档。</li><li><code>&amp;pattern</code>: 仅显示匹配模式的行，而不是整个文件。</li><li><code>ma</code>: 使用<code>a</code>标记文本的当前位置。</li><li><code>a</code>: 导航到标记<code>a</code>处。</li></ul><h2 id="示例" tabindex="-1"><a class="header-anchor" href="#示例" aria-hidden="true">#</a> 示例</h2><p>浏览<code>file.txt</code>文件。</p><div class="language-bash" data-ext="sh"><pre class="language-bash"><code><span class="token function">less</span> file.txt
</code></pre></div><p><code>ps</code>查看进程信息并通过<code>less</code>分页显示。</p><div class="language-bash" data-ext="sh"><pre class="language-bash"><code><span class="token function">ps</span> <span class="token parameter variable">-ef</span> <span class="token operator">|</span> <span class="token function">less</span>
</code></pre></div><p>查看<code>file.txt</code>文件并检索向后检索<code>1</code>字符串。</p><div class="language-bash" data-ext="sh"><pre class="language-bash"><code><span class="token function">less</span> file.txt 
/1
</code></pre></div>`,15),s=[a];function i(n,t){return c(),o("div",null,s)}const h=e(l,[["render",i],["__file","less.html.vue"]]);export{h as default};
